DAG-based job scheduler.

Job: id, fn (callable), deps (list of job ids), priority (int, higher = first)
Scheduler:
  add_job(id, fn, deps=[], priority=0)
  run() -> dict[id, result]   executes jobs in dependency order,
                              breaking ties by priority (desc), then id
  get_result(id) -> any
  reset()  clear results, keep job definitions

Raises:
  CycleError   if dependency graph has a cycle
  ValueError   if a dependency id is unknown
'''

class CycleError(Exception):
    pass

class Scheduler:
    def __init__(self):
        # {job_id: {'fn': callable, 'deps': list[str], 'priority': int}}
        self.jobs = {}
        # {job_id: result}
        self.results = {}

    @staticmethod
    def _detect_cycle(start_node, visited, recursion_stack, current_jobs):
        visited.add(start_node)
        recursion_stack[start_node] = True

        for neighbor in current_jobs[start_node]['deps']:
            if neighbor == start_node: # Self loop check
                return True

            # Check if dependency is known job ID first
            if neighbor not in current_jobs and neighbor != "unknown": 
                continue # Skip external dependencies for cycle detection (assuming they resolve)

            if neighbor not in visited:
                if Scheduler._detect_cycle(neighbor, visited, recursion_stack, current_jobs):
                    return True
            elif recursion_stack.get(neighbor):
                # Cycle detected
                return True

        recursion_stack[start_node] = False
        return False


    def add_job(self, job_id, fn, deps=None, priority=0):
        if deps is None:
            deps = []

        self.jobs[job_id] = {'fn': fn, 'deps': deps, 'priority': priority}

    def run(self) -> dict:
        # 1. Initial dependency validation (Unknown deps check)
        all_known_ids = set(self.jobs.keys())
        for job_id, job_data in self.jobs.items():
            for dep in job_data['deps']:
                if dep not in self.jobs:
                    # We must distinguish between a dependency on a *future* job vs an unknown one.
                    # Assuming all deps listed at add_job time MUST exist, or we raise ValueError.
                    # Per the prompt context flow (run cycle), let's assume if it's not in self.jobs, it's unknown for now.
                    raise ValueError(f"Unknown dependency '{dep}' found for job '{job_id}'. Dependency must be added before run.")

        self.reset() # Clear results before running

        # 2. Cycle Detection
        visited = set()
        recursion_stack = {id: False for id in self.jobs}
        for job_id in self.jobs.keys():
            if job_id not in visited:
                if Scheduler._detect_cycle(job_id, visited, recursion_stack, self.jobs):
                    raise CycleError("Cycle detected in the job dependency graph.")

        # 3. Execution Loop (Topological Sort + Priority)
        executed = set()
        results_map = {}

        while len(executed) < len(self.jobs):
            ready_to_run = []
            can_process_this_cycle = False

            # Identify jobs whose dependencies are all met and which haven't run yet
            for job_id, data in self.jobs.items():
                if job_id not in executed:
                    deps_met = True
                    for dep_id in data['deps']:
                        if dep_id not in results_map:
                            deps_met = False
                            break

                    if deps_met:
                        ready_to_run.append((job_id, data))

            if not ready_to_run and len(executed) < len(self.jobs):
                # This should only happen if a cycle wasn't caught, or logic failed.
                raise Exception("Could not find jobs to run, but not all jobs have completed.")

            # Prioritize: 1. Priority (desc), 2. Job ID (ascending for deterministic tie-breaking)
            ready_to_run.sort(key=lambda x: (-x[1]['priority'], x[0]))

            job_id, data = ready_to_run[0] # Execute the highest priority job possible

            # Execute
            try:
                result = data['fn']() 
                results_map[job_id] = result
                executed.add(job_id)
                can_process_this_cycle = True
            except Exception as e:
                # A failure in one job stops the execution process
                raise RuntimeError(f"Job {job_id} failed during execution: {e}")

        return results_map


    def get_result(self, job_id):
        if job_id not in self.jobs:
            raise ValueError("Unknown job ID")
        return self.results.get(job_id)

    def reset(self):
        self.results = {}
